        ctx.stroke();
        ctx.fillStyle = "#fff";
        ctx.font = "900 12px system-ui, -apple-system, Segoe UI, Roboto, sans-serif";
        ctx.textAlign = "center";
        ctx.textBaseline = "middle";
        ctx.fillText(label, p2.x, p2.y);
