      const a2 = pts[i2];
      const b2 = pts[i2 + 1];
      if (!a2 || !b2)
        continue;
      const abx = b2.x - a2.x;
      const aby = b2.y - a2.y;
      const abLen = Math.hypot(abx, aby);
      if (abLen <= 1e-9)
        continue;
