      const apy = y2 - a2.y;
      let t2 = (apx * abx + apy * aby) / (abLen * abLen);
      t2 = clamp3(t2, 0, 1);
      const cx = a2.x + abx * t2;
      const cy = a2.y + aby * t2;
      const dist = Math.hypot(x2 - cx, y2 - cy);
