function showEnigmeQuestion(id) {
  const app2 = document.getElementById("app");
  if (!app2)
    return;
  const enigmesMap = {
    enigme1: {
      id: "enigme1",
      title: "Quelle comp\xE9tence permet de lancer un ennemi avec un guerrier ?",
      options: ["Lancer d'alli\xE9", "Lancer d'ennemi", "Lancer de nain"],
      correctIndex: 1,
      rewardXp: 500
    },
    enigme2: {
      id: "enigme2",
      title: "Quelle comp\xE9tence de voleur permet de regagner du mana en tuant un ennemi ?",
      options: ["Assassinat", "Vol de mana", "Frappe sournoise"],
      correctIndex: 0,
      rewardXp: 500
    },
    enigme3: {
      id: "enigme3",
      title: "Quelle sp\xE9cialisation appartient au mage ?",
      options: ["Invocateur", "Chaman", "Illusioniste"],
      correctIndex: 0,
      rewardXp: 500
    }
  };
  const e2 = enigmesMap[id];
  if (!e2)
    return showEnigmesList();
  app2.innerHTML = `
        <img src="./imagesRPG/Fabienne_photo.png" class="background" alt="Enigme question">
        <div class="centered-content">
            <h1>${escapeHtml(String(e2.title))}</h1>
            ${e2.options.map((opt, idx) => `<button class="btn" data-enigme-ans="${idx}">${escapeHtml(opt)}</button>`).join("")}
            <div style="margin-top:12px;"><button class="btn" id="enigmeQuestionBackBtn">Retour</button></div>
        </div>
    `;
  app2.querySelectorAll("[data-enigme-ans]").forEach((btn) => btn.addEventListener("click", () => {
    const idx = Number(btn.getAttribute("data-enigme-ans"));
    if (idx === e2.correctIndex) {
      hero.enigmes = Object.assign({}, hero.enigmes ?? {}, { [id]: true });
      hero.gainXP ? hero.gainXP(e2.rewardXp) : hero.currentXP += e2.rewardXp;
      app2.innerHTML = `<img src='./imagesRPG/Fabienne_photo.png' class='background' alt='Fabienne'><div class='centered-content'><h1>Bonne r\xE9ponse !</h1><p>Vous gagnez <b>${e2.rewardXp} XP</b> !</p><button class='btn' id='enigmeDoneBackBtn'>Retour \xE9nigmes</button></div>`;
      document.getElementById("enigmeDoneBackBtn")?.addEventListener("click", showEnigmesList);
    } else {
      app2.innerHTML = `<img src='./imagesRPG/Fabienne_photo.png' class='background' alt='Fabienne'><div class='centered-content'><h1>Mauvaise r\xE9ponse !</h1><p>R\xE9essayez plus tard.</p><button class='btn' id='enigmeTryBackBtn'>Retour \xE9nigmes</button></div>`;
      document.getElementById("enigmeTryBackBtn")?.addEventListener("click", showEnigmesList);
    }
  }));
  document.getElementById("enigmeQuestionBackBtn")?.addEventListener("click", showEnigmesList);
}
function showQuetes(options = {}) {
  const app2 = document.getElementById("app");
  if (!app2)
    return;
  const qm = window.game?.questManager;
  const items = typeof qm?.getAll === "function" ? qm.getAll() : [];
  const tab = options.tab ?? "active";
  const isClaimed = (id) => {
    const p2 = qm?.getProgress?.(id);
    return p2?.status === "claimed";
  };
  const isVisible = (def) => {
    if (!def)
      return false;
    const gate = def.hiddenUntilClaimedQuestId;
    if (gate && !isClaimed(String(gate)))
      return false;
    return true;
  };
  const renderStatus = (p2) => {
    const s2 = String(p2?.status ?? "");
    if (s2 === "claimed")
      return "Termin\xE9e";
    if (s2 === "completed")
      return "\xC0 valider";
    if (s2 === "active")
      return "En cours";
    return "Non d\xE9marr\xE9e";
  };
  const renderProgress = (def, p2) => {
    if (!p2 || p2.status === void 0)
      return '<div style="color:#bbb;">Non d\xE9marr\xE9e.</div>';
    const stepIndex = Math.max(0, Math.floor(Number(p2.stepIndex ?? 0)));
    const step = Array.isArray(def?.steps) ? def.steps[stepIndex] : null;
    if (!step) {
      if (p2?.status === "claimed" || p2?.status === "completed") {
        return '<div style="margin-top:10px;color:#c8e6c9;font-weight:700;">Objectifs termin\xE9s.</div>';
      }
      return '<div style="color:#bbb;">Aucune \xE9tape.</div>';
    }
    const objectives = Array.isArray(step.objectives) ? step.objectives : [];
    const objState = p2.objectives ?? {};
    return `
            <div style="margin-top:10px;">
                <div style="font-weight:700;">\xC9tape: ${escapeHtml(String(step.title ?? step.id ?? ""))}</div>
                <div style="margin-top:8px;display:flex;flex-direction:column;gap:6px;">
                    ${objectives.map((o2) => {
      const cur = Math.max(0, Math.floor(Number(objState?.[String(o2.id)] ?? 0)));
      const t2 = String(o2.type ?? "");
      if (t2 === "counter") {
        const target = Math.max(1, Math.floor(Number(o2.target ?? 1)));
        const done2 = cur >= target;
        return `<div style="display:flex;justify-content:space-between;gap:12px;align-items:center;">
                                    <div style="color:${done2 ? "#c8e6c9" : "#ddd"};">${done2 ? "\u2714" : "\u2022"} ${escapeHtml(String(o2.description ?? o2.id ?? ""))}</div>
                                    <div style="color:#bbb;white-space:nowrap;">${cur}/${target}</div>
                                </div>`;
      }
      const done = cur >= 1;
      return `<div style="color:${done ? "#c8e6c9" : "#ddd"};">${done ? "\u2714" : "\u2022"} ${escapeHtml(String(o2.description ?? o2.id ?? ""))}</div>`;
    }).join("")}
                </div>
            </div>
        `;
  };
  app2.innerHTML = `
        <img src="ImagesRPG/imagesfond/village.jpg" class="background" alt="Qu\xEAtes">
        <div class="centered-content" style="max-width:900px;">
            <h1>Qu\xEAtes</h1>
            <div style="display:flex;gap:10px;justify-content:center;flex-wrap:wrap;margin-top:6px;">
                <button class="btn" id="quetesTabActiveBtn" style="min-width:180px;${tab === "active" ? "border:2px solid #ffd700;" : ""}">Qu\xEAtes</button>
                <button class="btn" id="quetesTabCompletedBtn" style="min-width:180px;${tab === "completed" ? "border:2px solid #ffd700;" : ""}">Qu\xEAtes termin\xE9es</button>
            </div>
            ${!qm ? '<div style="background:rgba(0,0,0,0.55);padding:14px;border-radius:10px;">Qu\xEAtes indisponibles (questManager manquant).</div>' : ""}
            <div style="display:flex;flex-direction:column;gap:14px;margin-top:14px;text-align:left;">
                ${items.filter(({ def, progress }) => {
    if (!isVisible(def))
      return false;
    const status = String(progress?.status ?? "");
    if (tab === "completed")
      return status === "claimed";
    return status !== "claimed";
  }).map(({ def, progress }) => {
    const status = renderStatus(progress);
    return `
                            <div style="background:rgba(0,0,0,0.55);border:1px solid rgba(255,255,255,0.08);padding:14px;border-radius:12px;">
                                <div style="display:flex;justify-content:space-between;gap:12px;align-items:flex-start;">
                                    <div>
                                        <div style="font-size:1.1em;font-weight:800;">${escapeHtml(String(def?.name ?? def?.id ?? "Qu\xEAte"))} ${def && def.__newlyUnlocked && !progress ? `<span style="display:inline-block;background:#4caf50;color:#fff;padding:2px 8px;border-radius:8px;font-size:0.7em;margin-left:8px;">Nouveau</span>` : ""}</div>
                                        <div style="color:#ddd;margin-top:4px;">${escapeHtml(String(def?.description ?? ""))}</div>
                                    </div>
                                    <div style="text-align:right;min-width:120px;">
                                        <div style="font-weight:800;color:#ffd700;">${escapeHtml(status)}</div>
                                        ${tab === "active" && !progress && qm && (def?.manualStartAllowed ?? true) ? `<button class="btn" data-quest-start="${escapeHtml(String(def?.id ?? ""))}" style="min-width:140px;margin-top:8px;">D\xE9marrer</button>` : tab === "active" && !progress ? `<div style="color:#999;margin-top:8px;">Qu\xEAte verrouill\xE9e</div>` : ""}
                                    </div>
                                </div>
                                ${renderProgress(def, progress)}
                            </div>
                        `;
  }).join("")}
                ${items.filter(({ def, progress }) => {
    if (!isVisible(def))
      return false;
    const status = String(progress?.status ?? "");
    if (tab === "completed")
      return status === "claimed";
    return status !== "claimed";
  }).length === 0 ? '<div style="background:rgba(0,0,0,0.55);padding:14px;border-radius:10px;">Aucune qu\xEAte.</div>' : ""}
            </div>
            <div style="margin-top:16px;display:flex;gap:12px;justify-content:center;">
                <button class="btn" id="quetesBackBtn">Retour</button>
            </div>
        </div>
    `;
  document.getElementById("quetesTabActiveBtn")?.addEventListener("click", () => {
    showQuetes({ ...options, tab: "active" });
  });
  document.getElementById("quetesTabCompletedBtn")?.addEventListener("click", () => {
    showQuetes({ ...options, tab: "completed" });
  });
  if (tab === "active") {
    app2.querySelectorAll("[data-quest-start]").forEach((btn) => {
      btn.addEventListener("click", () => {
        const id = btn.getAttribute("data-quest-start") ?? "";
        try {
          qm?.start?.(id);
        } catch (e2) {
          console.error("[quest] start error", e2);
        }
        showQuetes(options);
      });
    });
  }
  if (!document.__questUnlockedHandlerAdded) {
    document.addEventListener("quest:unlocked", () => {
      try {
        showQuetes(options);
      } catch (e2) {
      }
    });
    document.__questUnlockedHandlerAdded = true;
  }
  document.getElementById("quetesBackBtn")?.addEventListener("click", () => {
    if (options.onBack)
      options.onBack();
    else
      showVillage();
  });
}
